mapper.update:
UPDATE scheduling
SET physician_id = #{physicianId}, physician_name = #{physicianName},
    department_id = #{departmentId}, department_name = #{departmentName},
    work_date = #{workDate}, time_slot = #{timeSlot}, total_quota = #{totalQuota},
